function largestSwapPermutations(num) {
    const numStr = num.toString();
    const evenDigits = numStr.split('').filter(c => c % 2 === 0).sort((a, b) => b - a);
    const oddDigits = numStr.split('').filter(c => c % 2 !== 0).sort((a, b) => b - a);

    const result = numStr.split('').map(c => {
        if (c % 2 === 0) {
            return evenDigits.shift();
        } else {
            return oddDigits.shift();
        }
    }).join('');

    return parseInt(result, 10);
}
```


